-- AutoHire migration 026 — demo machinery: 300 machines across Rwanda, Dubai & China.
--
-- Rentable MACHINES (not road cars): cultivating (tractor / harvester / tiller) and
-- building (excavator / bulldozer / loader / crane / forklift). 264 of 300 are
-- ELECTRIC (85%+ green — electric tractors, e-excavators, e-forklifts) to match the
-- fleet's green story; the rest are diesel. Spread 100 Rwanda / 100 Dubai / 100 China
-- across all cities, priced in local currency (RWF / AED / CNY) with map coordinates.
--
-- Images are category-matched (a tractor shows a tractor, an excavator an excavator)
-- via loremflickr keywords — fixing the earlier pool that showed cars on machines.
--
-- REQUIRES migration-025 (the machinery enum values) to have been applied FIRST —
-- run 025 on its own, then this file. Also needs migration-023 (country/currency).
-- Safe to re-run: the machines are deleted + reinserted so re-running REFRESHES the
-- photos even on rows you already inserted. Remove for good with the same delete.
--
-- Apply in the Supabase SQL editor.

-- Machine-rental hosts (one heavy-equipment business per market).
insert into profiles
  (id, full_name, email, phone, role, joined_at, verification, rating_avg, rating_count,
   owner_type, business_name, payout_terms, insurance_type, vehicle_count)
values
  ('demo-mhost-rw', 'Rwanda Agri & Equipment', 'rentals@rwagri.example', '+250788300300', 'owner', '2025-03-01', 'verified', 4.8, 200, 'business', 'Rwanda Agri & Equipment', 'net_30', 'commercial', 100),
  ('demo-mhost-ae', 'Gulf Heavy Equipment', 'hire@gulfheavy.example', '+971563456789', 'owner', '2025-03-01', 'verified', 4.8, 200, 'business', 'Gulf Heavy Equipment', 'net_30', 'commercial', 100),
  ('demo-mhost-cn', 'Sino Machinery Rental', 'lease@sinomach.example', '+8613700137000', 'owner', '2025-03-01', 'verified', 4.8, 200, 'business', 'Sino Machinery Rental', 'net_30', 'commercial', 100)
on conflict (id) do nothing;

-- 300 demo machines. Delete-then-insert so re-running refreshes the images.
delete from listings where id like 'demo-machine-%';
insert into listings
  (id, title, host_id, owner_type, category, make, model, year, seats, transmission, fuel,
   price_per_day_rwf, price_currency, country, location, city, photos, features, booking_mode,
   rating_avg, rating_count, status, lat, lng)
